//! Regression coverage for issue #796.
//!
//! `scripts/install-node-dependencies.sh` classified reviewed npm deprecation
//! warnings by exact `name@version`. Transitive dependencies float without any
//! change on our side, so when `archiver-utils` resolved `glob` from `7.2.3` to
//! `10.5.0` the warning stopped matching, was treated as an unexpected
//! diagnostic, and failed both the `.vsix` packaging job and every desktop
//! build in the Desktop Release workflow.

use std::{
    fs,
    os::unix::fs::PermissionsExt,
    path::{Path, PathBuf},
    process::Command,
    time::{SystemTime, UNIX_EPOCH},
};

fn script() -> String {
    format!(
        "{}/scripts/install-node-dependencies.sh",
        env!("CARGO_MANIFEST_DIR")
    )
}

/// Builds a sandbox holding a fake `npm` that emits `stderr_lines`, so the
/// classifier can be exercised without touching the network.
fn sandbox(stderr_lines: &str) -> PathBuf {
    let nonce = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .expect("clock must be after epoch")
        .as_nanos();
    let dir = std::env::temp_dir().join(format!(
        "formal-ai-npm-classifier-{}-{nonce}",
        std::process::id()
    ));
    fs::create_dir_all(&dir).expect("sandbox must be created");
    let npm = dir.join("npm");
    fs::write(
        &npm,
        format!(
            "#!/usr/bin/env bash\n\
             if [ \"$1\" = \"--version\" ]; then echo 10.9.8; exit 0; fi\n\
             cat >&2 <<'STDERR'\n{stderr_lines}\nSTDERR\n\
             echo 'added 1 package'\nexit 0\n"
        ),
    )
    .expect("fake npm must be written");
    fs::set_permissions(&npm, fs::Permissions::from_mode(0o755))
        .expect("fake npm must be executable");
    dir
}

fn run_classifier(dir: &Path) -> std::process::Output {
    let path = format!(
        "{}:{}",
        dir.display(),
        std::env::var("PATH").unwrap_or_default()
    );
    Command::new("bash")
        .arg(script())
        .arg("ignored-directory")
        .env("PATH", path)
        .output()
        .expect("classifier must run")
}

#[test]
fn reviewed_deprecations_are_matched_by_package_name_not_pinned_version() {
    // The exact line that failed CI in run 29681451142.
    let dir = sandbox(
        "npm warn deprecated glob@10.5.0: Old versions of glob are not supported, and contain \
         widely publicized security vulnerabilities, which have been fixed in the current version.",
    );
    let output = run_classifier(&dir);
    fs::remove_dir_all(&dir).expect("sandbox must be removed");

    assert!(
        output.status.success(),
        "a floated version of a reviewed deprecation must not fail CI; stderr: {}",
        String::from_utf8_lossy(&output.stderr)
    );
    assert!(
        String::from_utf8_lossy(&output.stdout).contains("::notice title="),
        "the warning must be surfaced as an annotation rather than swallowed"
    );
}

#[test]
fn unreviewed_diagnostics_still_fail_the_build() {
    let dir = sandbox("npm warn deprecated totally-unknown-package@1.0.0: not reviewed");
    let output = run_classifier(&dir);
    fs::remove_dir_all(&dir).expect("sandbox must be removed");

    assert!(
        !output.status.success(),
        "loosening the version match must not turn the classifier into a rubber stamp"
    );
    assert!(String::from_utf8_lossy(&output.stderr).contains("Unexpected npm stderr"));
}

#[test]
fn scoped_package_names_are_parsed_without_losing_the_scope() {
    let dir = sandbox("npm warn deprecated @scope/pkg@2.0.0: scoped and unreviewed");
    let output = run_classifier(&dir);
    fs::remove_dir_all(&dir).expect("sandbox must be removed");

    // Reported verbatim: the scope must survive name extraction so that adding
    // "@scope/pkg" to the allowlist is what silences it.
    assert!(String::from_utf8_lossy(&output.stderr).contains("@scope/pkg@2.0.0"));
}

#[test]
fn verbose_tracing_exists_and_is_off_by_default() {
    let dir = sandbox("npm warn deprecated glob@10.5.0: reviewed");

    let quiet = run_classifier(&dir);
    assert!(
        !String::from_utf8_lossy(&quiet.stderr).contains("install-node-dependencies:"),
        "diagnostic tracing must stay off unless explicitly enabled"
    );
//! Shared fixtures for the release-workflow CI/CD unit tests.
//!
//! These helpers read the real workflow YAML from the repo and slice out
//! individual jobs/steps so the assertions in `workflow_release.rs` and
//! `release_publishing.rs` can stay focused and small.

use std::fs;

pub fn release_workflow() -> String {
    fs::read_to_string(format!(
        "{}/.github/workflows/release.yml",
        env!("CARGO_MANIFEST_DIR")
    ))
    .unwrap()
    .replace("\r\n", "\n")
}

pub fn desktop_release_workflow() -> String {
    fs::read_to_string(format!(
        "{}/.github/workflows/desktop-release.yml",
        env!("CARGO_MANIFEST_DIR")
    ))
    .unwrap()
    .replace("\r\n", "\n")
}

pub fn job_block<'a>(workflow: &'a str, job_name: &str) -> &'a str {
    let marker = format!("  {job_name}:\n");
    let start = workflow.find(&marker).unwrap();
    let body_start = start + marker.len();
    let rest = &workflow[body_start..];

    let next_job = rest
        .lines()
        .scan(0usize, |offset, line| {
            let current_offset = *offset;
            *offset += line.len() + 1;
            Some((current_offset, line))
        })
        .find_map(|(offset, line)| {
            let starts_at_job_indent = line.starts_with("  ") && !line.starts_with("    ");
            (starts_at_job_indent && line.trim_end().ends_with(':')).then_some(offset)
        });

    next_job.map_or_else(
        || &workflow[start..],
        |end| &workflow[start..body_start + end],
    )
}

pub fn workflow_step_block<'a>(job: &'a str, step_name: &str) -> &'a str {
    let marker = format!("      - name: {step_name}\n");
    let start = job.find(&marker).unwrap();
    let body_start = start + marker.len();
    let rest = &job[body_start..];

    let next_step = rest
        .lines()
        .scan(0usize, |offset, line| {
            let current_offset = *offset;
            *offset += line.len() + 1;
            Some((current_offset, line))
        })
        .find_map(|(offset, line)| line.starts_with("      - ").then_some(offset));

    next_step.map_or_else(|| &job[start..], |end| &job[start..body_start + end])
}

pub fn workflow_job_names(workflow: &str) -> Vec<&str> {
    let marker = "jobs:\n";
    let start = workflow.find(marker).unwrap() + marker.len();

    workflow[start..]
        .lines()
        .filter_map(|line| {
            let starts_at_job_indent = line.starts_with("  ") && !line.starts_with("    ");
            (starts_at_job_indent && line.trim_end().ends_with(':'))
                .then(|| line.trim().trim_end_matches(':'))
        })
        .collect()
}
#!/usr/bin/env rust-script
//! Check Rust files for maximum and warning line-count thresholds
//! Exits with error code 1 if any files exceed the hard limit
//!
//! Usage: rust-script scripts/check-file-size.rs
//!
//! ```cargo
//! [dependencies]
//! walkdir = "2"
//! ```

use std::fs;
use std::path::Path;
#[cfg(not(test))]
use std::process::{exit, Command};
use walkdir::WalkDir;

const FILE_LIMITS: &[FileLimit] = &[
    FileLimit {
        extension: "rs",
        max_lines: 1_000,
        warn_lines: 900,
        label: "Rust",
    },
    FileLimit {
        extension: "lino",
        max_lines: 1_500,
        warn_lines: 1_400,
        label: "Links Notation",
    },
];
const WORKER_JS_LIMIT: FileLimit = FileLimit {
    extension: "js",
    max_lines: 1_500,
    warn_lines: 1_400,
    label: "Worker JavaScript",
};
const EXCLUDE_PATTERNS: &[&str] = &["target", ".git", "node_modules"];
const EXCLUDE_PATH_FRAGMENTS: &[&str] = &["data/cache/wikidata/"];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct FileLimit {
    extension: &'static str,
    max_lines: usize,
    warn_lines: usize,
    label: &'static str,
}

fn normalized_path(path: &Path) -> String {
    path.to_string_lossy()
        .replace(std::path::MAIN_SEPARATOR, "/")
}

fn should_exclude(path: &Path) -> bool {
    let path_str = normalized_path(path);

    EXCLUDE_PATTERNS
        .iter()
        .any(|pattern| path_str.contains(pattern))
        || EXCLUDE_PATH_FRAGMENTS
            .iter()
            .any(|fragment| path_str.contains(fragment))
}

fn is_worker_js_path(path: &Path) -> bool {
    let path_str = normalized_path(path);
    let has_js_extension = path
        .extension()
        .and_then(|extension| extension.to_str())
        .is_some_and(|extension| extension.eq_ignore_ascii_case("js"));
    path_str.ends_with("src/web/formal_ai_worker.js")
        || (path_str.contains("/src/web/worker/") && has_js_extension)
}

fn file_limit(path: &Path) -> Option<&'static FileLimit> {
    if is_worker_js_path(path) {
        return Some(&WORKER_JS_LIMIT);
    }

    let ext = path.extension().and_then(|ext| ext.to_str())?;

    FILE_LIMITS.iter().find(|limit| limit.extension == ext)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct Finding {
    file: String,
    lines: usize,
    max_lines: usize,
    warn_lines: usize,
    label: &'static str,
}

#[derive(Debug, PartialEq, Eq)]
struct EmbeddedDataFinding {
    file: String,
    line: usize,
    message: String,
}

#[derive(Debug, PartialEq, Eq)]
struct CheckResult {
    warnings: Vec<Finding>,
    violations: Vec<Finding>,
    embedded_data_violations: Vec<EmbeddedDataFinding>,
}

#[derive(Debug, PartialEq, Eq)]
enum LineStatus {
    WithinLimit,
    Warning,
    Violation,
}

const fn classify_line_count(line_count: usize, limit: &FileLimit) -> LineStatus {
    if line_count > limit.max_lines {
        LineStatus::Violation
    } else if line_count > limit.warn_lines {
        LineStatus::Warning
    } else {
        LineStatus::WithinLimit
    }
}

fn relative_path(path: &Path, cwd: &Path) -> String {
    let relative = path
        .strip_prefix(cwd)
        .unwrap_or(path)
        .to_string_lossy()
        .to_string();

    relative.replace(std::path::MAIN_SEPARATOR, "/")
}

fn is_embedded_lino_data_line(line: &str) -> bool {
    let trimmed = line.trim_start();
    let declares_lino = (trimmed.starts_with("const ")
        || trimmed.starts_with("let ")
        || trimmed.starts_with("var "))
        && trimmed.contains("_LINO")
        && trimmed.contains('=');

    declares_lino && (trimmed.contains("= [") || trimmed.contains("= `"))
}

fn check_directory(cwd: &Path) -> CheckResult {
    let mut result = CheckResult {
        warnings: Vec::new(),
        violations: Vec::new(),
        embedded_data_violations: Vec::new(),
    };

    for entry in WalkDir::new(cwd)
        .into_iter()
        .filter_map(std::result::Result::ok)
        .filter(|e| e.file_type().is_file())
    {
        let path = entry.path();

        if should_exclude(path) {
            continue;
        }

        let limit = file_limit(path);
        let check_worker_data = is_worker_js_path(path);

        if limit.is_none() && !check_worker_data {
            continue;
        }

        match fs::read_to_string(path) {
            Ok(content) => {
                if let Some(limit) = limit {
                    let line_count = content.lines().count();

                    let finding = Finding {
                        file: relative_path(path, cwd),
                        lines: line_count,
                        max_lines: limit.max_lines,
                        warn_lines: limit.warn_lines,
                        label: limit.label,
                    };

                    match classify_line_count(line_count, limit) {
                        LineStatus::Violation => result.violations.push(finding),
                        LineStatus::Warning => result.warnings.push(finding),
                        LineStatus::WithinLimit => {}
                    }
                }

                if check_worker_data {
                    for (index, line) in content.lines().enumerate() {
                        if is_embedded_lino_data_line(line) {
                            result.embedded_data_violations.push(EmbeddedDataFinding {
                                file: relative_path(path, cwd),
                                line: index + 1,
                                message: "Worker JavaScript must load Links Notation data from data/seed via seed_loader.js, not embed _LINO arrays or template literals.".to_string(),
                            });
                        }
                    }
                }
            }
            Err(error) => {
                eprintln!("Warning: Could not read {}: {error}", path.display());
            }
        }
    }

    result
}

fn escape_annotation_property(value: &str) -> String {
    value
        .replace('%', "%25")
        .replace('\r', "%0D")
        .replace('\n', "%0A")
        .replace(':', "%3A")
        .replace(',', "%2C")
}

