#!/usr/bin/env rust-script
//! Check Rust files for maximum and warning line-count thresholds
//! Exits with error code 1 if any files exceed the hard limit
//!
//! Usage: rust-script scripts/check-file-size.rs
//!
//! ```cargo
//! [dependencies]
//! walkdir = "2"
//! ```

use std::fs;
use std::path::Path;
#[cfg(not(test))]
use std::process::{exit, Command};
use walkdir::WalkDir;

const FILE_LIMITS: &[FileLimit] = &[
    FileLimit {
        extension: "rs",
        max_lines: 1_000,
        warn_lines: 900,
        label: "Rust",
    },
    FileLimit {
        extension: "lino",
        max_lines: 1_500,
        warn_lines: 1_400,
        label: "Links Notation",
    },
];
const WORKER_JS_LIMIT: FileLimit = FileLimit {
    extension: "js",
    max_lines: 1_500,
    warn_lines: 1_400,
    label: "Worker JavaScript",
};
const EXCLUDE_PATTERNS: &[&str] = &["target", ".git", "node_modules"];
const EXCLUDE_PATH_FRAGMENTS: &[&str] = &["data/cache/wikidata/"];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct FileLimit {
    extension: &'static str,
    max_lines: usize,
    warn_lines: usize,
    label: &'static str,
}

fn normalized_path(path: &Path) -> String {
    path.to_string_lossy()
        .replace(std::path::MAIN_SEPARATOR, "/")
}

fn should_exclude(path: &Path) -> bool {
    let path_str = normalized_path(path);

    EXCLUDE_PATTERNS
        .iter()
        .any(|pattern| path_str.contains(pattern))
        || EXCLUDE_PATH_FRAGMENTS
            .iter()
            .any(|fragment| path_str.contains(fragment))
}

fn is_worker_js_path(path: &Path) -> bool {
    let path_str = normalized_path(path);
    let has_js_extension = path
        .extension()
        .and_then(|extension| extension.to_str())
        .is_some_and(|extension| extension.eq_ignore_ascii_case("js"));
    path_str.ends_with("src/web/formal_ai_worker.js")
        || (path_str.contains("/src/web/worker/") && has_js_extension)
}

fn file_limit(path: &Path) -> Option<&'static FileLimit> {
    if is_worker_js_path(path) {
        return Some(&WORKER_JS_LIMIT);
    }

    let ext = path.extension().and_then(|ext| ext.to_str())?;

    FILE_LIMITS.iter().find(|limit| limit.extension == ext)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct Finding {
    file: String,
    lines: usize,
    max_lines: usize,
    warn_lines: usize,
    label: &'static str,
}

#[derive(Debug, PartialEq, Eq)]
struct EmbeddedDataFinding {
    file: String,
    line: usize,
    message: String,
}

#[derive(Debug, PartialEq, Eq)]
struct CheckResult {
    warnings: Vec<Finding>,
    violations: Vec<Finding>,
    embedded_data_violations: Vec<EmbeddedDataFinding>,
}

#[derive(Debug, PartialEq, Eq)]
enum LineStatus {
    WithinLimit,
    Warning,
    Violation,
}

const fn classify_line_count(line_count: usize, limit: &FileLimit) -> LineStatus {
    if line_count > limit.max_lines {
        LineStatus::Violation
    } else if line_count > limit.warn_lines {
        LineStatus::Warning
    } else {
        LineStatus::WithinLimit
    }
}

fn relative_path(path: &Path, cwd: &Path) -> String {
    let relative = path
        .strip_prefix(cwd)
        .unwrap_or(path)
        .to_string_lossy()
        .to_string();

    relative.replace(std::path::MAIN_SEPARATOR, "/")
}

fn is_embedded_lino_data_line(line: &str) -> bool {
    let trimmed = line.trim_start();
    let declares_lino = (trimmed.starts_with("const ")
        || trimmed.starts_with("let ")
        || trimmed.starts_with("var "))
        && trimmed.contains("_LINO")
        && trimmed.contains('=');

    declares_lino && (trimmed.contains("= [") || trimmed.contains("= `"))
}

fn check_directory(cwd: &Path) -> CheckResult {
    let mut result = CheckResult {
        warnings: Vec::new(),
        violations: Vec::new(),
        embedded_data_violations: Vec::new(),
    };

    for entry in WalkDir::new(cwd)
        .into_iter()
        .filter_map(std::result::Result::ok)
        .filter(|e| e.file_type().is_file())
    {
        let path = entry.path();

        if should_exclude(path) {
            continue;
        }

        let limit = file_limit(path);
        let check_worker_data = is_worker_js_path(path);

        if limit.is_none() && !check_worker_data {
            continue;
        }

        match fs::read_to_string(path) {
            Ok(content) => {
                if let Some(limit) = limit {
                    let line_count = content.lines().count();

                    let finding = Finding {
                        file: relative_path(path, cwd),
                        lines: line_count,
                        max_lines: limit.max_lines,
                        warn_lines: limit.warn_lines,
                        label: limit.label,
                    };

                    match classify_line_count(line_count, limit) {
                        LineStatus::Violation => result.violations.push(finding),
                        LineStatus::Warning => result.warnings.push(finding),
                        LineStatus::WithinLimit => {}
                    }
                }

                if check_worker_data {
                    for (index, line) in content.lines().enumerate() {
                        if is_embedded_lino_data_line(line) {
                            result.embedded_data_violations.push(EmbeddedDataFinding {
                                file: relative_path(path, cwd),
                                line: index + 1,
                                message: "Worker JavaScript must load Links Notation data from data/seed via seed_loader.js, not embed _LINO arrays or template literals.".to_string(),
                            });
                        }
                    }
                }
            }
            Err(error) => {
                eprintln!("Warning: Could not read {}: {error}", path.display());
            }
        }
    }

    result
}

fn escape_annotation_property(value: &str) -> String {
    value
        .replace('%', "%25")
        .replace('\r', "%0D")
        .replace('\n', "%0A")
        .replace(':', "%3A")
        .replace(',', "%2C")
}

fn escape_annotation_message(value: &str) -> String {
    value
        .replace('%', "%25")
        .replace('\r', "%0D")
        .replace('\n', "%0A")
}

fn warning_annotation(finding: &Finding) -> String {
    let message = format!(
        "{} file has {} lines (approaching limit of {}). Consider extracting content to keep at or below {} lines and prevent review and merge conflicts.",
        finding.label, finding.lines, finding.max_lines, finding.warn_lines
    );

    format!(
        "::warning file={}::{}",
        escape_annotation_property(&finding.file),
        escape_annotation_message(&message)
    )
}

fn warnings_for_growing_paths<'a>(
    warnings: &'a [Finding],
    growing_paths: &[String],
) -> Vec<&'a Finding> {
    warnings
        .iter()
        .filter(|finding| growing_paths.contains(&finding.file))
        .collect()
}

fn growing_paths_from_numstat(numstat: &str) -> Vec<String> {
    numstat
        .lines()
        .filter_map(|line| {
            let mut fields = line.splitn(3, '\t');
            let added = fields.next()?.parse::<usize>().ok()?;
            let removed = fields.next()?.parse::<usize>().ok()?;
            let path = fields.next()?;
            (added > removed).then(|| path.to_string())
        })
name: 'Set up Docker Buildx (resilient)'
description: >
  Wrapper around docker/setup-buildx-action that first pre-pulls the pinned
  BuildKit image with retries and exponential backoff, and — when Docker Hub
  itself is unreachable — falls back to a pull-through registry mirror
  (mirror.gcr.io by default) before re-tagging the image to its canonical
  reference. Booting the docker-container driver otherwise pulls moby/buildkit
  straight from Docker Hub, and a transient registry timeout there fails the
  whole publish job even when nothing is wrong with the code or the build.
  Seeding the image locally first means the boot reuses the cached image
  instead of hitting the registry, and the mirror fallback keeps the seed
  working even during a full Docker Hub registry outage.
  See docs/case-studies/issue-69/README.md and the upstream investigations in
  link-foundation/box issues #97 and #100.
inputs:
  buildkit-image:
    description: 'Pinned BuildKit image used by the docker-container driver.'
    required: false
    default: 'moby/buildkit:buildx-stable-1'
  registry-mirror:
    description: >
      Pull-through Docker Hub mirror host used as a fallback when the canonical
      registry (registry-1.docker.io) is unreachable. mirror.gcr.io is Google's
      public pull-through cache of Docker Hub and is served from independent
      infrastructure, so it typically stays reachable during Docker Hub
      registry outages. Set to an empty string to disable the mirror fallback.
    required: false
    default: 'mirror.gcr.io'
  verbose:
    description: >
      Set to "true" to enable shell tracing (set -x) in the pre-pull step for
      debugging. Tracing is also enabled automatically when the workflow is run
      with step debug logging (RUNNER_DEBUG=1).
    required: false
    default: 'false'
runs:
  using: 'composite'
  steps:
    - name: Pre-pull BuildKit image (retry + registry-mirror fallback)
      shell: bash
      env:
        BUILDKIT_IMAGE: ${{ inputs.buildkit-image }}
        REGISTRY_MIRROR: ${{ inputs.registry-mirror }}
        VERBOSE: ${{ inputs.verbose }}
      run: |
        set -u
        # Verbose/debug tracing: opt-in via input, or automatic when the run is
        # started with "Enable debug logging" (RUNNER_DEBUG=1). Kept off by
        # default so normal logs stay readable.
        if [ "${VERBOSE}" = "true" ] || [ "${RUNNER_DEBUG:-}" = "1" ]; then
          echo "==> Verbose tracing enabled"
          set -x
        fi

        # Pull a reference with bounded retries and exponential backoff.
        # Returns 0 on the first successful pull, non-zero if all attempts fail.
        pull_with_retries() {
          ref="$1"
          # Attempts/backoff are overridable via env so the unit test can run
          # fast; the CI defaults stay at 5 attempts / 5s exponential backoff.
          attempts="${PREPULL_ATTEMPTS:-5}"
          delay="${PREPULL_DELAY:-5}"
          for attempt in $(seq 1 "$attempts"); do
            echo "==> Pulling ${ref} (attempt ${attempt}/${attempts})..."
            if docker pull "${ref}"; then
              return 0
            fi
            if [ "$attempt" -lt "$attempts" ]; then
              echo "==> Pull failed, waiting ${delay}s before next attempt..."
              sleep "$delay"
              delay=$((delay * 2))
            fi
          done
          return 1
        }

        # 1) Canonical Docker Hub. The common transient-blip case recovers here.
        if pull_with_retries "${BUILDKIT_IMAGE}"; then
          echo "==> BuildKit image cached locally from canonical registry; boot will not need a registry pull"
          exit 0
        fi

        # 2) Registry-mirror fallback. When Docker Hub's registry endpoint is
        #    fully unreachable (issue #69: registry-1.docker.io timed out for
        #    longer than a normal blip), the canonical pull above cannot recover
        #    no matter how many times it retries. mirror.gcr.io is a
        #    pull-through cache of Docker Hub on independent infrastructure, so
        #    it usually still serves the image. We pull from there and re-tag to
        #    the canonical reference so the docker-container driver boot finds it
        #    locally and never touches the failing registry.
        if [ -n "${REGISTRY_MIRROR}" ]; then
          mirror_ref="${REGISTRY_MIRROR}/${BUILDKIT_IMAGE}"
          echo "==> Canonical pull failed; trying registry mirror ${mirror_ref}"
          if pull_with_retries "${mirror_ref}"; then
            docker tag "${mirror_ref}" "${BUILDKIT_IMAGE}"
            echo "==> BuildKit image cached locally via mirror and tagged as ${BUILDKIT_IMAGE}; boot will reuse it"
            exit 0
          fi
          echo "==> Mirror pull from ${REGISTRY_MIRROR} also failed"
        fi

        # Non-fatal: fall through to setup-buildx, which will attempt its own
        # pull during boot. This preserves the previous behaviour in the worst
        # case while making the common transient-failure case recover.
        echo "==> WARNING: could not pre-pull ${BUILDKIT_IMAGE} from canonical registry or mirror; letting setup-buildx try its own boot pull"

    - name: Set up Docker Buildx
      uses: docker/setup-buildx-action@v4
      with:
        driver-opts: image=${{ inputs.buildkit-image }}
