use std::path::Path;
#[cfg(not(test))]
use std::process::{exit, Command};
use walkdir::WalkDir;

const FILE_LIMITS: &[FileLimit] = &[
    FileLimit {
        extension: "rs",
        max_lines: 1_000,
        warn_lines: 900,
